// Ensure markdown tables have blank lines before/after so Showdown parses them
let md = $input.first().json.markdownReportContent || '';
md = md.replace(/(^|\n)([^\n]*\|[^\n]*\n\|[-| :]+\|[^\n]*(?:\n\|[^\n]*)*)/g, (match, prefix, table) => {
  return prefix + '\n' + table + '\n';
});

// Fetch email config from app_config if trigger values are null
const SUPABASE_URL = 'https://qsirioazmsmrrfoltrhn.supabase.co';
const SUPABASE_API_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InFzaXJpb2F6bXNtcnJmb2x0cmhuIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MjgwOTU2MSwiZXhwIjoyMDg4Mzg1NTYxfQ.oqvzwBcCwYTI1pe1MPnNQn64Yc3e-mozT2yFOYi3iAk';
const trigger = $input.first().json;

let recipient_email = trigger.recipient_email;
let bcc_email = trigger.bcc_email;
if (!recipient_email) {
  try {
    const rows = await this.helpers.httpRequest({
      method: 'GET',
      url: `${SUPABASE_URL}/rest/v1/app_config?key=in.(recipient_email,bcc_email)&select=key,value`,
      headers: { 'apikey': SUPABASE_API_KEY, 'Authorization': `Bearer ${SUPABASE_API_KEY}` }
    });
    for (const row of rows) {
      if (row.key === 'recipient_email') recipient_email = row.value;
      if (row.key === 'bcc_email') bcc_email = row.value;
    }
  } catch (e) {
    recipient_email = 'eric@agileadtesting.com';
    bcc_email = '';
  }
}

return [{
  json: {
    markdownReportContent: md,
    emailAddress: trigger.emailAddress,
    subjectLine: trigger.subjectLine,
    recipient_email: recipient_email,
    bcc_email: bcc_email || ''
  }
}];
